  const toast = useToast()

  const subscribe = () => {
    form.post('/subscribe', {
      preserveScroll: true,
      onSuccess: () => {
        toast.add({
          severity: 'success',
          summary: t('success'),
          detail: t('success_detail'),
          life: 6000,
        })
        form.reset()
      },
    })
  }
